// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract CredzOnChain {
    struct Event {
        string name;
        string description;
        uint256 eventType;
        uint256 timestamp;
        address organizer;
    }

    mapping(uint256 => Event) public events;
    mapping(uint256 => mapping(address => bool)) public hasClaimed;

    uint256 private nextEventId;

    event EventCreated(uint256 indexed eventId, string name, address indexed organizer);
    event BadgeIssued(uint256 indexed eventId, address indexed recipient, address indexed issuer);

    constructor() {
        nextEventId = 0;
    }

    function createEvent(string memory _name, string memory _description, uint256 _eventType, uint256 _timestamp) public returns (uint256) {
        uint256 eventId = nextEventId++;
        events[eventId] = Event({
            name: _name,
            description: _description,
            eventType: _eventType,
            timestamp: _timestamp,
            organizer: msg.sender
        });
        emit EventCreated(eventId, _name, msg.sender);
        return eventId;
    }

    function issueBadge(uint256 _eventId, address _recipient) public {
        require(events[_eventId].organizer == msg.sender, "Only the event organizer can issue badges.");
        require(!hasClaimed[_eventId][_recipient], "Badge already claimed for this event by this recipient.");

        hasClaimed[_eventId][_recipient] = true;
        emit BadgeIssued(_eventId, _recipient, msg.sender);
    }

    function getEvent(uint256 _eventId) public view returns (string memory, string memory, uint256, uint256, address) {
        Event storage eventData = events[_eventId];
        return (eventData.name, eventData.description, eventData.eventType, eventData.timestamp, eventData.organizer);
    }

    function checkClaimStatus(uint256 _eventId, address _wallet) public view returns (bool) {
        return hasClaimed[_eventId][_wallet];
    }
}

